import type { StateCreator } from 'zustand';
import {
  OrderDetailStatus,
  type OrderDetailState,
  type PointsTransaction,
} from '../models/orderDetail.model';

export interface OrderDetailActions {
  setOrderDetailStatus: (status: OrderDetailStatus) => void;
  setOrderDetail: (orderDetail: PointsTransaction, transactionId?: string) => void;
  reset: () => void;
}

export interface OrderDetailSlice {
  orderDetail: OrderDetailState;
  orderDetailActions: OrderDetailActions;
}

const INITIAL_ORDER_DETAIL_STATE: OrderDetailState = {
  orderDetail: undefined,
  status: OrderDetailStatus.IDLE,
  error: undefined,
  transactionId: undefined,
};

export const createOrderDetailSlice: StateCreator<
  OrderDetailSlice,
  [],
  [],
  OrderDetailSlice
> = (set) => ({
  orderDetail: INITIAL_ORDER_DETAIL_STATE,
  orderDetailActions: {
    setOrderDetailStatus: (status) =>
      set((state) => ({
        orderDetail: { ...state.orderDetail, status },
      })),
    setOrderDetail: (orderDetail, transactionId) =>
      set((state) => ({
        orderDetail: {
          ...state.orderDetail,
          orderDetail,
          status: OrderDetailStatus.SUCCESS,
          error: undefined,
          transactionId,
        },
      })),
    reset: () =>
      set({
        orderDetail: INITIAL_ORDER_DETAIL_STATE,
      }),
  },
});

import { StateCreator } from 'zustand';

import {
  AirlineMilesSlice,
  createAirlineMilesSlice,
  createMarketplaceSlice,
  createParameterPointsProgramSlice,
  createPermissionSlice,
  createPointsExtractSlice,
  createPointsProductsSlice,
  createRescueSlice,
  MarketplaceSlice,
  ParameterPointsProgramSlice,
  PermissionSlice,
  PointsExtractSlice,
  PointsProductsSlice,
  RescueSlice,
} from '../index';

export type RewardsProgramRootStore = ParameterPointsProgramSlice &
  PermissionSlice &
  AirlineMilesSlice &
  PointsExtractSlice &
  PointsProductsSlice &
  RescueSlice &
  MarketplaceSlice;

type Slice<T> = StateCreator<RewardsProgramRootStore, [], [], T>;
const asSlice = <T>(slice: StateCreator<RewardsProgramRootStore, [], [], T>) =>
  slice as Slice<T>;

export function setRewardsProgramSlices<T extends RewardsProgramRootStore>(
  ...a: Parameters<Slice<T>>
) {
  return {
    ...asSlice<ParameterPointsProgramSlice>(createParameterPointsProgramSlice)(
      ...a,
    ),
    ...asSlice<PermissionSlice>(createPermissionSlice)(...a),
    ...asSlice<AirlineMilesSlice>(createAirlineMilesSlice)(...a),
    ...asSlice<PointsExtractSlice>(createPointsExtractSlice)(...a),
    ...asSlice<PointsProductsSlice>(createPointsProductsSlice)(...a),
    ...asSlice<RescueSlice>(createRescueSlice)(...a),
    ...asSlice<MarketplaceSlice>(createMarketplaceSlice)(...a),
  };
}

