import type { StateCreator } from 'zustand';
import {
  OrderDetailStatus,
  type OrderDetailState,
  type PointsTransaction,
} from '../models/orderDetail.model';

export interface OrderDetailActions {
  setOrderDetailStatus: (status: OrderDetailStatus) => void;
  setOrderDetail: (orderDetail: PointsTransaction, transactionId?: string) => void;
  reset: () => void;
}

export interface OrderDetailSlice {
  orderDetail: OrderDetailState;
  orderDetailActions: OrderDetailActions;
}

const INITIAL_ORDER_DETAIL_STATE: OrderDetailState = {
  orderDetail: undefined,
  status: OrderDetailStatus.IDLE,
  error: undefined,
  transactionId: undefined,
};

export const createOrderDetailSlice: StateCreator<
  OrderDetailSlice,
  [],
  [],
  OrderDetailSlice
> = (set) => ({
  orderDetail: INITIAL_ORDER_DETAIL_STATE,
  orderDetailActions: {
    setOrderDetailStatus: (status) =>
      set((state) => ({
        orderDetail: { ...state.orderDetail, status },
      })),
    setOrderDetail: (orderDetail, transactionId) =>
      set((state) => ({
        orderDetail: {
          ...state.orderDetail,
          orderDetail,
          status: OrderDetailStatus.SUCCESS,
          error: undefined,
          transactionId,
        },
      })),
    reset: () =>
      set({
        orderDetail: INITIAL_ORDER_DETAIL_STATE,
      }),
  },
});

